export function translateSandi(val, dict) {
  if (val === null || val === undefined) return val;
  let s = String(val).trim();
  if (s.endsWith('.0')) s = s.slice(0, -2);
  if (s in dict) return s + ' - ' + dict[s];
  let s2 = s.replace(/^0+/, '') || '0';
  if (s2 in dict) return s + ' - ' + dict[s2];
  for (const pad of [2,3]) { const z = s.padStart(pad,'0'); if (z in dict) return s + ' - ' + dict[z]; }
  return String(val);
}
